function report = runPhaseAStepMatrix(options)
%RUNPHASEASTEPMATRIX Render and validate discontinuous height steps.
%
% The 2.5-D surface contains low and high horizontal half-planes. Rays that
% would hit the omitted vertical wall are invalid. Reference surface points
% are projected into the moving camera and visibility is checked by tracing
% the moving ray back through the independently defined step surface.
%
% Traceability: algorithm description Secs. 10.2, 11.2, and 13;
% synthetic piecewise-plane, occlusion, and depth-discontinuity cases.

arguments
    options.StepHeightMetres (1, :) double ...
        {mustBeFinite, mustBePositive} = [25, 50, 100]
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [512, 512]
    options.Display (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
src = fullfile(root, "src");
oldPath = path;
addpath(src);
cleanup = onCleanup(@() path(oldPath));

nh = numel(options.StepHeightMetres);
stepHeight = [options.StepHeightMetres(:); options.StepHeightMetres(:)];
direction = [repmat("along-track", nh, 1); ...
    repmat("cross-track", nh, 1)];
n = numel(stepHeight);
[x, y] = meshgrid(1:options.ImageSize(2), 1:options.ImageSize(1));
p = [x(:), y(:)];
np = size(p, 1);

referenceValidFraction = nan(n, 1);
movingValidFraction = nan(n, 1);
referenceSurfaceFraction = nan(n, 1);
movingSurfaceFraction = nan(n, 1);
omittedWallFraction = nan(n, 1);
insideMovingFraction = nan(n, 1);
movingVisibleFraction = nan(n, 1);
occludedFraction = nan(n, 1);
referenceFalseValidRate = nan(n, 1);
movingFalseValidRate = nan(n, 1);
maximumWarpError = nan(n, 1);
truthHeightLevels = nan(n, 1);
maximumDn = nan(n, 1);
renderSeconds = nan(n, 1);

timer = tic;
for k = 1:n
    id = "step_" + direction(k) + "_" + string(stepHeight(k));
    renderer = SyntheticPinholeRenderer( ...
        id, options.ImageSize, SurfaceType="step", ...
        StepHeightMetres=stepHeight(k), StepDirection=direction(k), ...
        Supersample=2, PsfSigmaPixels=0.5, TextureSeed=200 + k);
    geom = HeightSweepGeometry( ...
        renderer.ReferenceCamera, renderer.MovingCamera);

    rt = tic;
    pair = renderer.renderPair;
    renderSeconds(k) = toc(rt);
    referenceValidFraction(k) = nnz(pair.ReferenceValid) / np;
    movingValidFraction(k) = nnz(pair.MovingValid) / np;
    maximumDn(k) = max([pair.ReferenceImage(:); pair.MovingImage(:)]);

    [~, z, vr] = PinholeStepOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [~, ~, vm] = PinholeStepOracle.intersect( ...
        renderer.MovingCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [wt, vc, inside, visible] = PinholeStepOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.StepHeightMetres, ...
        renderer.StepDirectionENU, ...
        PositionMetres=renderer.StepPositionMetres);
    referenceSurfaceFraction(k) = nnz(vr) / np;
    movingSurfaceFraction(k) = nnz(vm) / np;
    omittedWallFraction(k) = 1 - referenceSurfaceFraction(k);
    insideMovingFraction(k) = nnz(inside) / np;
    movingVisibleFraction(k) = nnz(visible) / max(1, nnz(inside));
    occludedFraction(k) = nnz(inside & ~visible) / max(1, nnz(inside));
    referenceFalseValidRate(k) = nnz( ...
        pair.ReferenceValid(:) & ~vr) / np;
    movingFalseValidRate(k) = nnz(pair.MovingValid(:) & ~vm) / np;
    truthHeightLevels(k) = numel(unique(z(vr)));

    pv = p(vc, :);
    zv = z(vc);
    [wg, vg] = geom.warp(pv, zv);
    d = vecnorm(wg - wt(vc, :), 2, 2);
    d(~vg) = NaN;
    maximumWarpError(k) = max(d, [], "omitmissing");
end
seconds = toc(timer);

results = table(direction, stepHeight, referenceValidFraction, ...
    movingValidFraction, referenceSurfaceFraction, movingSurfaceFraction, ...
    omittedWallFraction, insideMovingFraction, movingVisibleFraction, ...
    occludedFraction, referenceFalseValidRate, movingFalseValidRate, ...
    maximumWarpError, truthHeightLevels, maximumDn, renderSeconds, ...
    VariableNames=["Direction", "StepHeightMetres", ...
    "ReferenceImageValidFraction", "MovingImageValidFraction", ...
    "ReferenceSurfaceFraction", "MovingSurfaceFraction", ...
    "OmittedWallFraction", "InsideMovingImageFraction", ...
    "MovingVisibleFraction", "OccludedFraction", ...
    "ReferenceFalseValidRate", "MovingFalseValidRate", ...
    "MaximumOracleWarpErrorPixels", "TruthHeightLevels", ...
    "MaximumDn", "RenderSeconds"]);
summary = struct( ...
    "Cases", height(results), ...
    "MinimumReferenceImageValidFraction", min(referenceValidFraction), ...
    "MinimumMovingImageValidFraction", min(movingValidFraction), ...
    "MaximumOmittedWallFraction", max(omittedWallFraction), ...
    "MaximumOccludedFraction", max(occludedFraction), ...
    "MaximumReferenceFalseValidRate", max(referenceFalseValidRate), ...
    "MaximumMovingFalseValidRate", max(movingFalseValidRate), ...
    "MaximumOracleWarpErrorPixels", max(maximumWarpError), ...
    "MaximumDn", max(maximumDn), ...
    "Seconds", seconds);
report = struct("Results", results, "Summary", summary, ...
    "ImageSize", options.ImageSize);

fprintf("Phase A height-step matrix: %d cases\n", height(results));
fprintf("  Minimum image-valid fractions [reference moving]: [%.6f %.6f]\n", ...
    summary.MinimumReferenceImageValidFraction, ...
    summary.MinimumMovingImageValidFraction);
fprintf("  Maximum omitted-wall fraction: %.6f\n", ...
    summary.MaximumOmittedWallFraction);
fprintf("  Maximum moving occlusion fraction: %.6f\n", ...
    summary.MaximumOccludedFraction);
fprintf("  Maximum renderer false-valid rates [reference moving]: " + ...
    "[%.3e %.3e]\n", summary.MaximumReferenceFalseValidRate, ...
    summary.MaximumMovingFalseValidRate);
fprintf("  Max oracle/geometry EPE: %.3e pixels\n", ...
    summary.MaximumOracleWarpErrorPixels);
fprintf("  Runtime: %.3f s\n", seconds);
if options.Display
    disp(results);
end

clear cleanup
end
